'use client';

import { useState } from 'react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Textarea } from '@/components/ui/textarea';
import { useToast } from '@/hooks/use-toast';

export default function CouponsPage() {
  const { toast } = useToast();
  const [form, setForm] = useState({
    code: '',
    description: '',
    discountType: 'percentage',
    discountValue: '',
    startDate: '',
    endDate: '',
    usageLimit: '',
    minOrder: '',
    active: true,
  });

  const onChange = (
    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
  ) => {
    const { name, value } = e.target;
    setForm((s) => ({ ...s, [name]: value }));
  };

  const onSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    toast({ title: 'Coupon saved', description: `Code ${form.code || '(no code)'} created/updated.` });
    // TODO: integrate API
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-xl font-semibold">Coupons</h2>
        <p className="text-muted-foreground text-sm">Create and manage coupon codes.</p>
      </div>

      <form onSubmit={onSubmit} className="space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <Label htmlFor="code">Code</Label>
            <Input id="code" name="code" placeholder="WELCOME10" value={form.code} onChange={onChange} required />
          </div>

          <div className="space-y-2">
            <Label htmlFor="discountType">Discount Type</Label>
            <Select
              value={form.discountType}
              onValueChange={(v) => setForm((s) => ({ ...s, discountType: v }))}
            >
              <SelectTrigger id="discountType">
                <SelectValue placeholder="Select type" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="percentage">Percentage (%)</SelectItem>
                <SelectItem value="fixed">Fixed Amount</SelectItem>
              </SelectContent>
            </Select>
          </div>

          <div className="space-y-2">
            <Label htmlFor="discountValue">Discount Value</Label>
            <Input
              id="discountValue"
              name="discountValue"
              type="number"
              min="0"
              step="0.01"
              placeholder={form.discountType === 'percentage' ? 'e.g. 10 for 10%' : 'e.g. 5.00'}
              value={form.discountValue}
              onChange={onChange}
              required
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="usageLimit">Usage Limit</Label>
            <Input id="usageLimit" name="usageLimit" type="number" min="0" placeholder="e.g. 100" value={form.usageLimit} onChange={onChange} />
          </div>

          <div className="space-y-2">
            <Label htmlFor="minOrder">Minimum Order Amount</Label>
            <Input id="minOrder" name="minOrder" type="number" min="0" step="0.01" placeholder="e.g. 20.00" value={form.minOrder} onChange={onChange} />
          </div>

          <div className="space-y-2">
            <Label htmlFor="startDate">Start Date</Label>
            <Input id="startDate" name="startDate" type="date" value={form.startDate} onChange={onChange} />
          </div>

          <div className="space-y-2">
            <Label htmlFor="endDate">End Date</Label>
            <Input id="endDate" name="endDate" type="date" value={form.endDate} onChange={onChange} />
          </div>
        </div>

        <div className="flex items-center justify-between rounded-md border p-4">
          <div>
            <Label htmlFor="active">Active</Label>
            <p className="text-xs text-muted-foreground">Toggle to enable or disable this coupon.</p>
          </div>
          <Switch id="active" checked={form.active} onCheckedChange={(v) => setForm((s) => ({ ...s, active: v }))} />
        </div>

        <div className="space-y-2">
          <Label htmlFor="description">Description</Label>
          <Textarea id="description" name="description" placeholder="Optional notes" value={form.description} onChange={onChange} />
        </div>

        <div className="flex gap-3">
          <Button type="submit">Save Coupon</Button>
          <Button type="button" variant="outline" onClick={() => setForm({ code: '', description: '', discountType: 'percentage', discountValue: '', startDate: '', endDate: '', usageLimit: '', minOrder: '', active: true })}>Reset</Button>
        </div>
      </form>
    </div>
  );
}
